noncompliant:
/* This is a C-style comment */
/* These can be problematic because
   /* they don't nest properly */ and this might cause issues */

/* Multi-line C comments
   can be accidentally
   terminated early */

compliant:
// This is a C++ style comment
// Multiple lines are handled cleanly
// Each line starts with //

// C++ comments are preferred because:
// - They don't have nesting problems
// - They're easier to comment out blocks
// - Less typing required
